import ast

class ASTParser(ast.NodeVisitor):
    def __init__(self):
        self.classes = []
        self.functions = []
        self.calls = []

    def visit_ClassDef(self, node):
        self.classes.append(node.name)
        self.generic_visit(node)

    def visit_FunctionDef(self, node):
        self.functions.append(node.name)
        self.generic_visit(node)

    def visit_Call(self, node):
        if isinstance(node.func, ast.Name):
            self.calls.append(node.func.id)
        self.generic_visit(node)

# Usage
code = '''
class MyAgent:
    def __init__(self):
        self.model = load_model()

    def run(self):
        return self.model.predict()
'''

tree = ast.parse(code)
parser = ASTParser()
parser.visit(tree)
print(f"Classes: {parser.classes}")
print(f"Functions: {parser.functions}")

import subprocess
from pathlib import Path

def analyze_branch_pattern(repo: Path) -> dict:
    """Analyze if repo uses trunk-based or feature branches"""

    # Get all branch names
    branches = subprocess.run(
        ['git', 'branch', '-a'],
        cwd=repo, capture_output=True, text=True
    ).stdout.split('\n')

    # Get commit count per branch
    branch_stats = {}
    for branch in branches:
        if branch.strip():
            name = branch.strip().replace('* ', '')
            count = subprocess.run(
                ['git', 'rev-list', '--count', name],
                cwd=repo, capture_output=True, text=True
            ).stdout.strip()
            branch_stats[name] = int(count)

    return {
        'total_branches': len(branch_stats),
        'branch_stats': branch_stats,
        'pattern': 'feature-branches' if len(branch_stats) > 3 else 'trunk-based'
    }

# Mini graph with typed state
from langgraph.graph import StateGraph
from pydantic import BaseModel

class MiniState(BaseModel):
    input: str
    outputs: list = []
    final: str = ""

def node_a(state):
    return {'outputs': [f"processed_{state['input']}"]}

def node_b(state):
    return {'outputs': [f"validated_{state['input']}"]}

def combiner(state):
    combined = " + ".join(state['outputs'])
    return {'final': combined}

graph = StateGraph(MiniState)
graph.add_node('a', node_a)
graph.add_node('b', node_b)
graph.add_node('combine', combiner)
graph.set_entry_point('a')
graph.add_edge('a', 'b')
graph.add_edge('b', 'combine')

app = graph.compile()
result = app.invoke({'input': 'test'})

from pydantic import BaseModel
from typing import List, Optional

class EvaluationResult(BaseModel):
    score: int
    argument: str
    cited_evidence: List[str]
    confidence: float

def create_judge_prompt(evidence: str, rubric: str) -> str:
    """Create a structured judgment prompt"""
    return f"""
You are an expert evaluator. Analyze the following evidence against the rubric.

EVIDENCE:
{evidence}

RUBRIC:
{rubric}

Provide your evaluation in this exact JSON format:
{{
    "score": <integer 1-5>,
    "argument": "<your reasoning>",
    "cited_evidence": ["<evidence id>", ...],
    "confidence": <float 0-1>
}}

Respond with ONLY valid JSON, no additional text.
"""

def parse_llm_response(response: str, retries: int = 3) -> Optional[EvaluationResult]:
    """Parse LLM response with retry logic"""
    import json

    for attempt in range(retries):
        try:
            # Try to find JSON in response
            json_match = response.find('{')
            if json_match >= 0:
                json_str = response[json_match:]
                data = json.loads(json_str)
                return EvaluationResult(**data)
        except (json.JSONDecodeError, ValidationError):
            continue

    return None

