from typing import List, Optional
from enum import Enum

class Verdict(Enum):
    APPROVED = "approved"
    REJECTED = "rejected"
    NEEDS_REVISION = "needs_revision"

class JudgeOpinion:
    def __init__(self, judge_id: str, score: int, argument: str, evidence: List[str]):
        self.judge_id = judge_id
        self.score = score
        self.argument = argument
        self.evidence = evidence

class SynthesisEngine:
    def __init__(self):
        self.rules = []

    def add_rule(self, rule_fn):
        """Add a deterministic rule"""
        self.rules.append(rule_fn)

    def synthesize(self, opinions: List[JudgeOpinion]) -> dict:
        """Combine multiple judge opinions into final verdict"""
        # Apply rules in order
        for rule in self.rules:
            result = rule(opinions)
            if result:
                return result

        # Default: average score
        avg_score = sum(o.score for o in opinions) / len(opinions)

        return {
            'verdict': Verdict.APPROVED if avg_score >= 3 else Verdict.REJECTED,
            'final_score': avg_score,
            'consensus': len([o for o in opinions if o.score >= 3]) / len(opinions)
        }

# Example rule: security override
def security_override(opinions: List[JudgeOpinion]) -> Optional[dict]:
    """If any judge identifies security issues, cap the score"""
    security_keywords = ['security', 'vulnerability', 'exploit', 'injection']

    for opinion in opinions:
        for keyword in security_keywords:
            if keyword in opinion.argument.lower():
                return {
                    'verdict': Verdict.REJECTED,
                    'reason': 'Security issue detected',
                    'capped_score': max(2, opinion.score - 2)
                }
    return None

# Rule priority system
class RulePriority:
    SECURITY = 1      # Highest priority
    SAFETY = 2
    ACCURACY = 3
    STYLE = 4         # Lowest priority

class DeterministicSynthesizer:
    def __init__(self):
        self.rules = {}

    def register_rule(self, name: str, priority: int, rule_fn):
        """Register a rule with priority"""
        if priority not in self.rules:
            self.rules[priority] = []
        self.rules[priority].append((name, rule_fn))

    def apply(self, context: dict) -> dict:
        """Apply rules in priority order"""
        for priority in sorted(self.rules.keys()):
            for name, rule_fn in self.rules[priority]:
                result = rule_fn(context)
                if result:
                    return {
                        'applied_rule': name,
                        'priority': priority,
                        'result': result
                    }
        return {'result': 'no_rules_triggered'}

# Usage
synth = DeterministicSynthesizer()
synth.register_rule('security_check', RulePriority.SECURITY, 
    lambda ctx: {'reject': True} if ctx.get('has_vuln') else None)
